@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Info.Name &mdash; @entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info.Name</span>
                        <span class="file-meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    private sealed record FileEntry(FileInfo Info, string? Error);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-c1fb6473c9934e25a6ded54905dd5ac3/Components/FileDropZone.razor.js");

        _dotNetRef = DotNetObjectReference.Create(this);
        await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isOver)
    {
        _isDragOver = isOver;
        InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnFilesDropped(DroppedFile[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            string? error = f.Size > MaxSizeBytes
                ? $"File exceeds 10 MB limit ({FormatSize(f.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("disposeDropZone", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    public sealed record DroppedFile(string Name, long Size, string Type);
}

const handlers = new WeakMap();

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    const onDragEnter = (e) => {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
        }
    };

    const onDragOver = (e) => {
        e.preventDefault();
    };

    const onDragLeave = (e) => {
        e.preventDefault();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    const onDrop = (e) => {
        e.preventDefault();
        dragCounter = 0;

        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'application/octet-stream' });
        }

        if (files.length > 0) {
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        } else {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    handlers.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function disposeDropZone(element) {
    const h = handlers.get(element);
    if (!h) return;

    element.removeEventListener('dragenter', h.onDragEnter);
    element.removeEventListener('dragover', h.onDragOver);
    element.removeEventListener('dragleave', h.onDragLeave);
    element.removeEventListener('drop', h.onDrop);
    handlers.delete(element);
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    min-width: 0;
}

.file-name {
    font-weight: 500;
    word-break: break-all;
}

.file-meta {
    font-size: 0.85rem;
    color: #6c757d;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
    word-break: break-all;
}

.btn-remove {
    flex-shrink: 0;
    margin-left: 1rem;
    padding: 0.25rem 0.75rem;
    border: 1px solid #dc3545;
    border-radius: 4px;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background: #dc3545;
    color: #fff;
}

